import { createContext, useContext, useState } from 'react';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);

  const login = (email, name = 'Rahul Sharma') => {
    setUser({
      name,
      email,
      initials: name.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2),
      stream: 'Science (PCM)',
      class: 'Class 12',
      city: 'Delhi',
      phone: '+91 98765 43210',
      linkedin: 'linkedin.com/in/rahulsharma',
      github: 'github.com/rahulsharma',
      objective: 'Aspiring software engineer with strong foundation in CSE fundamentals, seeking to leverage academic excellence and problem-solving skills in a dynamic tech environment.',
      skills: 'Python, C++, Java, React, Machine Learning, SQL, Git',
      academics: { p10: 92, p12: 88, cgpa: 8.4, entrance: 145, exam: 'JEE Main', category: 'General', state: 'Delhi', extra: 'Sports (State Level)', branch: 'Computer Science (CSE)' },
    });
  };

  const logout = () => setUser(null);

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
